392		protected void successfulAuthentication(HttpServletRequest request, HttpServletResponse response, FilterChain chain,
393				Authentication authResult) throws IOException, ServletException {
394			SecurityContext context = this.securityContextHolderStrategy.createEmptyContext();
395			context.setAuthentication(authResult);
396			this.securityContextHolderStrategy.setContext(context);
397			this.securityContextRepository.saveContext(context, request, response);
398			if (this.logger.isDebugEnabled()) {
399				this.logger.debug(LogMessage.format("Set SecurityContextHolder to %s", authResult));
400			}
401			this.rememberMeServices.loginSuccess(request, response, authResult);
402			if (this.eventPublisher != null) {
403				this.eventPublisher.publishEvent(new InteractiveAuthenticationSuccessEvent(authResult, this.getClass()));
404			}
405			this.successHandler.onAuthenticationSuccess(request, response, authResult);
406		}
