408		/**
409		 * Default behaviour for unsuccessful authentication.
410		 * <ol>
411		 * <li>Clears the {@link SecurityContextHolder}</li>
412		 * <li>Stores the exception in the session (if it exists or
413		 * <tt>allowSessionCreation</tt> is set to <tt>true</tt>)</li>
414		 * <li>Informs the configured <tt>RememberMeServices</tt> of the failed login</li>
415		 * <li>Delegates additional behaviour to the
416		 * {@link AuthenticationFailureHandler}.</li>
417		 * </ol>
418		 */
419		protected void unsuccessfulAuthentication(HttpServletRequest request, HttpServletResponse response,
420				AuthenticationException failed) throws IOException, ServletException {
421			this.securityContextHolderStrategy.clearContext();
422			this.logger.trace("Failed to process authentication request", failed);
423			this.logger.trace("Cleared SecurityContextHolder");
424			this.logger.trace("Handling authentication failure");
425			this.rememberMeServices.loginFail(request, response);
426			this.failureHandler.onAuthenticationFailure(request, response, failed);
427		}
